function selectScenicWaypoints(features, startLat, startLng, targetDistanceKm) {
  if (features.length === 0) return [];
  const idealRadius = targetDistanceKm / (2 * Math.PI);
  const minDist = idealRadius * 0.3;
  const maxDist = idealRadius * 1.2;
  const inRange = features.filter((f) => f.distance >= minDist && f.distance <= maxDist);
  const pool2 = inRange.length >= 3 ? inRange : features;
  const typePriority = {
    park: 5,
    river: 4,
    trail: 4,
    coastline: 4,
    lake: 3,
    footpath: 2,
    green_space: 1
  };
  const sortedPool = [...pool2].sort((a, b) => (typePriority[b.type] || 0) - (typePriority[a.type] || 0));
  const quadrants = [null, null, null, null];
  for (const feature of sortedPool) {
    const quadrant = Math.floor(feature.bearing / 90) % 4;
    if (!quadrants[quadrant]) quadrants[quadrant] = feature;
  }
  const selectedFeatures = quadrants.filter(Boolean);
  if (selectedFeatures.length < 2) {
    return sortedPool.slice(0, 3).map((f) => ({
      lat: f.lat,
      lng: f.lng,
      name: f.name || f.type,
      type: f.type
    }));
  }
  selectedFeatures.sort((a, b) => a.bearing - b.bearing);
  return selectedFeatures.map((f) => ({
    lat: f.lat,
    lng: f.lng,
    name: f.name || f.type,
    type: f.type
  }));
}
