      id: gr.id,
      name: gr.title || "Group Run",
      description: gr.description || "",
      creatorId: gr.hostUserId,
      creatorName: host?.name || "Unknown",
      meetingPoint: gr.meetingPoint || null,
      meetingLat: gr.meetingLat || null,
